1	`timescale 1ns / 1ps
2	
3	/**
4	 * cfar_ca.v
5	 *
6	 * Cell-Averaging CFAR (Constant False Alarm Rate) Detector
7	 * for the AERIS-10 phased-array radar.
8	 *
9	 * Replaces the simple magnitude threshold detector in radar_system_top.v
10	 * (lines 474-514) with a proper adaptive-threshold CFAR algorithm.
11	 *
12	 * Architecture:
13	 *   Phase 1 (BUFFER): As Doppler processor outputs arrive, compute |I|+|Q|
14	 *     magnitude and store in BRAM. Address = {range_bin, doppler_bin}.
15	 *     When CFAR is disabled, applies simple threshold pass-through.
16	 *
17	 *   Phase 2 (CFAR): After frame_complete pulse from Doppler processor,
18	 *     process each Doppler column independently:
19	 *     a) Read 64 magnitudes from BRAM for one Doppler bin (ST_COL_LOAD)
20	 *     b) Compute initial sliding window sums (ST_CFAR_INIT)
21	 *     c) Slide CUT through all 64 range bins:
22	 *        - 3 sub-cycles per CUT:
23	 *          ST_CFAR_THR: register noise_sum (mode select + cross-multiply)
24	 *          ST_CFAR_MUL: compute alpha * noise_sum_reg in DSP
25	 *          ST_CFAR_CMP: compare CUT magnitude against threshold + update window
26	 *     d) Advance to next Doppler column (ST_COL_NEXT)
27	 *
28	 * CFAR Modes (cfg_cfar_mode):
29	 *   2'b00 = CA-CFAR:  noise = leading_sum + lagging_sum
30	 *   2'b01 = GO-CFAR:  noise = max(leading_sum * lag_cnt, lagging_sum * lead_cnt)
31	 *                      normalized — picks larger average
32	 *   2'b10 = SO-CFAR:  noise = min(leading_sum * lag_cnt, lagging_sum * lead_cnt)
33	 *   2'b11 = Reserved (falls back to CA-CFAR)
34	 *
35	 * Threshold computation:
36	 *   threshold = (alpha * noise_sum) >> ALPHA_FRAC_BITS
37	 *   Host sets alpha in Q4.4 fixed-point, pre-compensated for training cell count.
38	 *   Example: for T=8 cells per side (16 total), desired Pfa=1e-4:
39	 *     alpha_statistical ≈ 4.88
40	 *     alpha_fpga = alpha_statistical / 16 = 0.305 → Q4.4 ≈ 0x05
41	 *   Or host can set alpha per training cell if it accounts for count.
42	 *
43	 * Edge handling:
44	 *   At range boundaries where the full window doesn't fit, only available
45	 *   training cells are used. The noise estimate naturally reduces, raising
46	 *   false alarm rate at edges — acceptable for radar (edge bins are
47	 *   typically clutter).
48	 *
49	 * Timing:
50	 *   Phase 2 takes ~(66 + T + 3*64) * 32 ≈ 8500 cycles per frame @ 100 MHz
51	 *   = 85 µs. Frame period @ PRF=1932 Hz, 32 chirps = 16.6 ms. Fits easily.
52	 *   (3 cycles per CUT due to pipeline: THR → MUL → CMP)
53	 *
54	 * Resources:
55	 *   - 1 BRAM18K for magnitude buffer (2048 x 17 bits)
56	 *   - 1 DSP48 for alpha multiply
57	 *   - ~300 LUTs for FSM + sliding window + comparators
58	 *
59	 * Clock domain: clk (100 MHz, same as Doppler processor)
60	 */
61	
62	module cfar_ca #(
63	    parameter NUM_RANGE_BINS   = 64,
64	    parameter NUM_DOPPLER_BINS = 32,
65	    parameter MAG_WIDTH        = 17,
66	    parameter ALPHA_WIDTH      = 8,
67	    parameter MAX_GUARD        = 8,
68	    parameter MAX_TRAIN        = 16
69	) (
70	    input wire clk,
71	    input wire reset_n,
72	
73	    // ========== DOPPLER PROCESSOR INPUTS ==========
74	    input wire [31:0] doppler_data,
75	    input wire        doppler_valid,
76	    input wire [4:0]  doppler_bin_in,
77	    input wire [5:0]  range_bin_in,
78	    input wire        frame_complete,
79	
80	    // ========== CONFIGURATION ==========
81	    input wire [3:0]  cfg_guard_cells,
82	    input wire [4:0]  cfg_train_cells,
83	    input wire [ALPHA_WIDTH-1:0] cfg_alpha,
84	    input wire [1:0]  cfg_cfar_mode,
85	    input wire        cfg_cfar_enable,
86	    input wire [15:0] cfg_simple_threshold,
87	
88	    // ========== DETECTION OUTPUTS ==========
89	    output reg        detect_flag,
90	    output reg        detect_valid,
91	    output reg [5:0]  detect_range,
92	    output reg [4:0]  detect_doppler,
93	    output reg [MAG_WIDTH-1:0] detect_magnitude,
94	    output reg [MAG_WIDTH-1:0] detect_threshold,
95	
96	    // ========== STATUS ==========
97	    output reg [15:0] detect_count,
98	    output wire       cfar_busy,
99	    output reg [7:0]  cfar_status
100	);
101	
102	// ============================================================================
103	// INTERNAL PARAMETERS
104	// ============================================================================
105	localparam TOTAL_CELLS = NUM_RANGE_BINS * NUM_DOPPLER_BINS;
106	localparam ADDR_WIDTH  = 11;
107	localparam COL_BITS    = 5;
108	localparam ROW_BITS    = 6;
109	localparam SUM_WIDTH   = MAG_WIDTH + 6;  // 23 bits: sum of up to 64 magnitudes
110	localparam PROD_WIDTH  = SUM_WIDTH + ALPHA_WIDTH;  // 31 bits
111	localparam ALPHA_FRAC_BITS = 4;  // Q4.4
112	
113	// ============================================================================
114	// FSM STATES
115	// ============================================================================
116	localparam [3:0] ST_IDLE       = 4'd0,
117	                 ST_BUFFER     = 4'd1,
118	                 ST_COL_LOAD   = 4'd2,
119	                 ST_CFAR_INIT  = 4'd3,
120	                 ST_CFAR_THR   = 4'd4,  // Register noise_sum (mode select + cross-multiply)
121	                 ST_CFAR_MUL   = 4'd8,  // Compute alpha * noise_sum_reg in DSP
122	                 ST_CFAR_CMP   = 4'd5,  // Compare + update window
123	                 ST_COL_NEXT   = 4'd6,
124	                 ST_DONE       = 4'd7;
125	
126	reg [3:0] state;
127	assign cfar_busy = (state != ST_IDLE);
128	
129	// ============================================================================
130	// MAGNITUDE COMPUTATION (combinational)
131	// ============================================================================
132	wire signed [15:0] dop_i = doppler_data[15:0];
133	wire signed [15:0] dop_q = doppler_data[31:16];
134	wire [15:0] abs_i = dop_i[15] ? (~dop_i + 16'd1) : dop_i;
135	wire [15:0] abs_q = dop_q[15] ? (~dop_q + 16'd1) : dop_q;
136	wire [MAG_WIDTH-1:0] cur_mag = {1'b0, abs_i} + {1'b0, abs_q};
137	
138	// ============================================================================
139	// MAGNITUDE BRAM (2048 x 17 bits)
140	// ============================================================================
141	reg                    mag_we;
142	reg [ADDR_WIDTH-1:0]   mag_waddr;
143	reg [MAG_WIDTH-1:0]    mag_wdata;
144	reg [ADDR_WIDTH-1:0]   mag_raddr;
145	reg [MAG_WIDTH-1:0]    mag_rdata;
146	
147	(* ram_style = "block" *) reg [MAG_WIDTH-1:0] mag_mem [0:TOTAL_CELLS-1];
148	
149	always @(posedge clk) begin
150	    if (mag_we)
151	        mag_mem[mag_waddr] <= mag_wdata;
152	    mag_rdata <= mag_mem[mag_raddr];
153	end
154	
155	// ============================================================================
156	// COLUMN LINE BUFFER (64 x 17 bits — distributed RAM)
157	// ============================================================================
158	reg [MAG_WIDTH-1:0] col_buf [0:NUM_RANGE_BINS-1];
159	reg [ROW_BITS:0] col_load_idx;
160	
161	// ============================================================================
162	// SLIDING WINDOW STATE
163	// ============================================================================
164	reg [SUM_WIDTH-1:0] leading_sum;
165	reg [SUM_WIDTH-1:0] lagging_sum;
166	reg [ROW_BITS:0]    leading_count;
167	reg [ROW_BITS:0]    lagging_count;
168	reg [ROW_BITS:0]    cut_idx;
169	reg [COL_BITS-1:0]  col_idx;
170	
171	// Registered config (captured at frame start)
172	reg [3:0]  r_guard;
173	reg [4:0]  r_train;
174	reg [ALPHA_WIDTH-1:0] r_alpha;
175	reg [1:0]  r_mode;
176	reg        r_enable;
177	reg [15:0] r_simple_thr;
178	
179	// Threshold pipeline registers
180	reg [SUM_WIDTH-1:0]  noise_sum_reg;   // Stage 1: registered noise_sum_comb output
181	reg [PROD_WIDTH-1:0] noise_product;   // Stage 2: alpha * noise_sum_reg
182	reg [MAG_WIDTH-1:0]  adaptive_thr;
183	
184	// Init counter for computing initial lagging sum
185	reg [ROW_BITS:0] init_idx;
186	
187	// ============================================================================
188	// SLIDING WINDOW DELTA COMPUTATION (combinational)
189	// ============================================================================
190	// Compute net delta to leading_sum and lagging_sum when CUT advances by 1.
191	// All deltas computed combinationally, applied as a single NBA per register.
192	
193	// Indices of cells entering/leaving the window when CUT moves from k to k+1:
194	//   Leading: new training cell at index k+1-G-1 = k-G (was closest guard cell)
195	//            cell falling off at index k+1-G-T-1 = k-G-T
196	//   Lagging: cell leaving at index k+G+1 (enters guard zone)
197	//            new cell entering at index k+1+G+T (at far end)
198	
199	wire signed [ROW_BITS+1:0] lead_add_idx = $signed({1'b0, cut_idx}) - $signed({1'b0, r_guard});
200	wire signed [ROW_BITS+1:0] lead_rem_idx = $signed({1'b0, cut_idx}) - $signed({1'b0, r_guard}) - $signed({1'b0, r_train});
201	wire signed [ROW_BITS+1:0] lag_rem_idx  = $signed({1'b0, cut_idx}) + $signed({1'b0, r_guard}) + 1;
202	wire signed [ROW_BITS+1:0] lag_add_idx  = $signed({1'b0, cut_idx}) + 1 + $signed({1'b0, r_guard}) + $signed({1'b0, r_train});
203	
204	wire lead_add_valid = (lead_add_idx >= 0) && (lead_add_idx < NUM_RANGE_BINS);
205	wire lead_rem_valid = (lead_rem_idx >= 0) && (lead_rem_idx < NUM_RANGE_BINS);
206	wire lag_rem_valid  = (lag_rem_idx  >= 0) && (lag_rem_idx  < NUM_RANGE_BINS);
207	wire lag_add_valid  = (lag_add_idx  >= 0) && (lag_add_idx  < NUM_RANGE_BINS);
208	
209	// Safe col_buf read with bounds checking (combinational)
210	wire [MAG_WIDTH-1:0] lead_add_val = lead_add_valid ? col_buf[lead_add_idx[ROW_BITS-1:0]] : {MAG_WIDTH{1'b0}};
211	wire [MAG_WIDTH-1:0] lead_rem_val = lead_rem_valid ? col_buf[lead_rem_idx[ROW_BITS-1:0]] : {MAG_WIDTH{1'b0}};
212	wire [MAG_WIDTH-1:0] lag_rem_val  = lag_rem_valid  ? col_buf[lag_rem_idx[ROW_BITS-1:0]]  : {MAG_WIDTH{1'b0}};
213	wire [MAG_WIDTH-1:0] lag_add_val  = lag_add_valid  ? col_buf[lag_add_idx[ROW_BITS-1:0]]  : {MAG_WIDTH{1'b0}};
214	
215	// Net deltas
216	wire signed [SUM_WIDTH:0] lead_delta = (lead_add_valid ? $signed({1'b0, lead_add_val}) : 0)
217	                                      - (lead_rem_valid ? $signed({1'b0, lead_rem_val}) : 0);
218	wire signed [1:0] lead_cnt_delta = (lead_add_valid ? 1 : 0) - (lead_rem_valid ? 1 : 0);
219	
220	wire signed [SUM_WIDTH:0] lag_delta = (lag_add_valid ? $signed({1'b0, lag_add_val}) : 0)
221	                                     - (lag_rem_valid ? $signed({1'b0, lag_rem_val}) : 0);
222	wire signed [1:0] lag_cnt_delta = (lag_add_valid ? 1 : 0) - (lag_rem_valid ? 1 : 0);
223	
224	// ============================================================================
225	// NOISE ESTIMATE COMPUTATION (combinational for CFAR mode selection)
226	// ============================================================================
227	reg [SUM_WIDTH-1:0] noise_sum_comb;
228	
229	always @(*) begin
230	    case (r_mode)
231	    2'b00, 2'b11: begin  // CA-CFAR
232	        noise_sum_comb = leading_sum + lagging_sum;
233	    end
234	    2'b01: begin  // GO-CFAR: pick sum from side with greater average
235	        if (leading_count > 0 && lagging_count > 0) begin
236	            // leading_avg > lagging_avg ↔ leading_sum * lagging_count > lagging_sum * leading_count
237	            if (leading_sum * lagging_count > lagging_sum * leading_count)
238	                noise_sum_comb = leading_sum;
239	            else
240	                noise_sum_comb = lagging_sum;
241	        end else if (leading_count > 0)
242	            noise_sum_comb = leading_sum;
243	        else
244	            noise_sum_comb = lagging_sum;
245	    end
246	    2'b10: begin  // SO-CFAR: pick sum from side with smaller average
247	        if (leading_count > 0 && lagging_count > 0) begin
248	            if (leading_sum * lagging_count < lagging_sum * leading_count)
249	                noise_sum_comb = leading_sum;
250	            else
251	                noise_sum_comb = lagging_sum;
252	        end else if (leading_count > 0)
253	            noise_sum_comb = leading_sum;
254	        else
255	            noise_sum_comb = lagging_sum;
256	    end
257	    default:
258	        noise_sum_comb = leading_sum + lagging_sum;
259	    endcase
260	end
261	
262	// ============================================================================
263	// MAIN FSM
264	// ============================================================================
265	always @(posedge clk or negedge reset_n) begin
266	    if (!reset_n) begin
267	        state          <= ST_IDLE;
268	        detect_flag    <= 1'b0;
269	        detect_valid   <= 1'b0;
270	        detect_range   <= 6'd0;
271	        detect_doppler <= 5'd0;
272	        detect_magnitude <= {MAG_WIDTH{1'b0}};
273	        detect_threshold <= {MAG_WIDTH{1'b0}};
274	        detect_count   <= 16'd0;
275	        cfar_status    <= 8'd0;
276	        mag_we         <= 1'b0;
277	        mag_waddr      <= {ADDR_WIDTH{1'b0}};
278	        mag_wdata      <= {MAG_WIDTH{1'b0}};
279	        mag_raddr      <= {ADDR_WIDTH{1'b0}};
280	        col_load_idx   <= 0;
281	        col_idx        <= 0;
282	        cut_idx        <= 0;
283	        leading_sum    <= 0;
284	        lagging_sum    <= 0;
285	        leading_count  <= 0;
286	        lagging_count  <= 0;
287	        init_idx       <= 0;
288	        noise_sum_reg  <= 0;
289	        noise_product  <= 0;
290	        adaptive_thr   <= 0;
291	        r_guard        <= 4'd2;
292	        r_train        <= 5'd8;
293	        r_alpha        <= 8'h30;
294	        r_mode         <= 2'b00;
295	        r_enable       <= 1'b0;
296	        r_simple_thr   <= 16'd10000;
297	    end else begin
298	        // Defaults: clear one-shot outputs
299	        detect_valid <= 1'b0;
300	        detect_flag  <= 1'b0;
301	        mag_we       <= 1'b0;
302	
303	        case (state)
304	        // ================================================================
305	        // ST_IDLE: Wait for first Doppler output
306	        // ================================================================
307	        ST_IDLE: begin
308	            cfar_status <= 8'd0;
309	
310	            if (doppler_valid) begin
311	                // Capture configuration at frame start
312	                r_guard      <= cfg_guard_cells;
313	                r_train      <= (cfg_train_cells == 0) ? 5'd1 : cfg_train_cells;
314	                r_alpha      <= cfg_alpha;
315	                r_mode       <= cfg_cfar_mode;
316	                r_enable     <= cfg_cfar_enable;
317	                r_simple_thr <= cfg_simple_threshold;
318	
319	                // Buffer first sample
320	                mag_we    <= 1'b1;
321	                mag_waddr <= {range_bin_in, doppler_bin_in};
322	                mag_wdata <= cur_mag;
323	
324	                // Simple threshold pass-through when CFAR disabled
325	                if (!cfg_cfar_enable) begin
326	                    detect_flag  <= (cur_mag > {1'b0, cfg_simple_threshold});
327	                    detect_valid <= 1'b1;
328	                    detect_range     <= range_bin_in;
329	                    detect_doppler   <= doppler_bin_in;
330	                    detect_magnitude <= cur_mag;
331	                    detect_threshold <= {1'b0, cfg_simple_threshold};
332	                    if (cur_mag > {1'b0, cfg_simple_threshold})
333	                        detect_count <= detect_count + 1;
334	                end
335	
336	                state <= ST_BUFFER;
337	            end
338	        end
339	
340	        // ================================================================
341	        // ST_BUFFER: Store magnitudes until frame complete
342	        // ================================================================
343	        ST_BUFFER: begin
344	            cfar_status <= {4'd1, 4'd0};
345	
346	            if (doppler_valid) begin
347	                mag_we    <= 1'b1;
348	                mag_waddr <= {range_bin_in, doppler_bin_in};
349	                mag_wdata <= cur_mag;
350	
351	                if (!r_enable) begin
352	                    detect_flag  <= (cur_mag > {1'b0, r_simple_thr});
353	                    detect_valid <= 1'b1;
354	                    detect_range     <= range_bin_in;
355	                    detect_doppler   <= doppler_bin_in;
356	                    detect_magnitude <= cur_mag;
357	                    detect_threshold <= {1'b0, r_simple_thr};
358	                    if (cur_mag > {1'b0, r_simple_thr})
359	                        detect_count <= detect_count + 1;
360	                end
361	            end
362	
363	            if (frame_complete) begin
364	                if (r_enable) begin
365	                    col_idx      <= 0;
366	                    col_load_idx <= 0;
367	                    mag_raddr    <= {6'd0, 5'd0};
368	                    state        <= ST_COL_LOAD;
369	                end else begin
370	                    state <= ST_DONE;
371	                end
372	            end
373	        end
374	
375	        // ================================================================
376	        // ST_COL_LOAD: Read one Doppler column from BRAM
377	        // ================================================================
378	        // BRAM has 1-cycle read latency. Pipeline: present addr cycle N,
379	        // capture data cycle N+1.
380	        ST_COL_LOAD: begin
381	            cfar_status <= {4'd2, 1'b0, col_idx[2:0]};
382	
383	            if (col_load_idx == 0) begin
384	                // First address already presented, advance to range=1
385	                mag_raddr    <= {6'd1, col_idx};
386	                col_load_idx <= 1;
387	            end else if (col_load_idx <= NUM_RANGE_BINS) begin
388	                // Capture previous read
389	                col_buf[col_load_idx - 1] <= mag_rdata;
390	
391	                if (col_load_idx < NUM_RANGE_BINS) begin
392	                    mag_raddr <= {col_load_idx[ROW_BITS-1:0] + 6'd1, col_idx};
393	                end
394	
395	                col_load_idx <= col_load_idx + 1;
396	            end
397	
398	            if (col_load_idx == NUM_RANGE_BINS + 1) begin
399	                // Column fully loaded → initialize CFAR window
400	                state         <= ST_CFAR_INIT;
401	                init_idx      <= 0;
402	                leading_sum   <= 0;
403	                lagging_sum   <= 0;
404	                leading_count <= 0;
405	                lagging_count <= 0;
406	                cut_idx       <= 0;
407	            end
408	        end
409	
410	        // ================================================================
411	        // ST_CFAR_INIT: Compute initial window sums for CUT=0
412	        // ================================================================
413	        // CUT=0 has no leading cells. Lagging cells are at
414	        // indices [guard+1 .. guard+train] (if they exist).
415	        // Iterate one training cell per cycle.
416	        ST_CFAR_INIT: begin
417	            cfar_status <= {4'd3, 1'b0, col_idx[2:0]};
418	
419	            if (init_idx < r_train) begin
420	                if ((r_guard + 1 + init_idx) < NUM_RANGE_BINS) begin
421	                    lagging_sum   <= lagging_sum + col_buf[r_guard + 1 + init_idx];
422	                    lagging_count <= lagging_count + 1;
423	                end
424	                init_idx <= init_idx + 1;
425	            end else begin
426	                // Initial sums ready → begin CFAR sliding
427	                state <= ST_CFAR_THR;
428	            end
429	        end
430	
431	        // ================================================================
432	        // ST_CFAR_THR: Register noise estimate (mode select + cross-multiply)
433	        // ================================================================
434	        // Pipeline stage 1: register the combinational noise_sum_comb
435	        // output. This breaks the critical path:
436	        //   leading_sum → cross-multiply (GO/SO) → mux → alpha*noise DSP
437	        // into two shorter paths:
438	        //   Cycle 1: leading_sum → cross-multiply → mux → noise_sum_reg
439	        //   Cycle 2: noise_sum_reg → alpha * noise_sum_reg → noise_product
440	        ST_CFAR_THR: begin
441	            cfar_status <= {4'd4, 1'b0, col_idx[2:0]};
442	
443	            noise_sum_reg <= noise_sum_comb;
444	            state <= ST_CFAR_MUL;
445	        end
446	
447	        // ================================================================
448	        // ST_CFAR_MUL: Compute alpha * noise_sum_reg in DSP
449	        // ================================================================
450	        // Pipeline stage 2: multiply registered noise sum by alpha.
451	        // This is a clean registered-input → DSP path.
452	        ST_CFAR_MUL: begin
453	            cfar_status <= {4'd4, 1'b1, col_idx[2:0]};
454	
455	            noise_product <= r_alpha * noise_sum_reg;
456	            state <= ST_CFAR_CMP;
457	        end
458	
459	        // ================================================================
460	        // ST_CFAR_CMP: Compare CUT against threshold + update window
461	        // ================================================================
462	        ST_CFAR_CMP: begin
463	            cfar_status <= {4'd5, 1'b0, col_idx[2:0]};
464	
465	            // Threshold = noise_product >> ALPHA_FRAC_BITS
466	            // Saturate to MAG_WIDTH bits
467	            if (noise_product[PROD_WIDTH-1:ALPHA_FRAC_BITS+MAG_WIDTH] != 0)
468	                adaptive_thr <= {MAG_WIDTH{1'b1}};  // Saturate
469	            else
470	                adaptive_thr <= noise_product[ALPHA_FRAC_BITS +: MAG_WIDTH];
471	
472	            // Output detection result
473	            detect_magnitude <= col_buf[cut_idx[ROW_BITS-1:0]];
474	            detect_range     <= cut_idx[ROW_BITS-1:0];
475	            detect_doppler   <= col_idx;
476	            detect_valid     <= 1'b1;
477	
478	            // Compare: threshold computed this cycle from noise_product
479	            begin : threshold_compare
480	                reg [MAG_WIDTH-1:0] thr_val;
481	                if (noise_product[PROD_WIDTH-1:ALPHA_FRAC_BITS+MAG_WIDTH] != 0)
482	                    thr_val = {MAG_WIDTH{1'b1}};
483	                else
484	                    thr_val = noise_product[ALPHA_FRAC_BITS +: MAG_WIDTH];
485	
486	                detect_threshold <= thr_val;
487	
488	                if (col_buf[cut_idx[ROW_BITS-1:0]] > thr_val) begin
489	                    detect_flag  <= 1'b1;
490	                    detect_count <= detect_count + 1;
491	                end
492	            end
493	
494	            // Update sliding window for next CUT
495	            if (cut_idx < NUM_RANGE_BINS - 1) begin
496	                // Apply pre-computed deltas (single NBA per register)
497	                leading_sum   <= $unsigned($signed({1'b0, leading_sum}) + lead_delta);
498	                leading_count <= $unsigned($signed({1'b0, leading_count}) + {{(ROW_BITS){lead_cnt_delta[1]}}, lead_cnt_delta});
499	                lagging_sum   <= $unsigned($signed({1'b0, lagging_sum}) + lag_delta);
500	                lagging_count <= $unsigned($signed({1'b0, lagging_count}) + {{(ROW_BITS){lag_cnt_delta[1]}}, lag_cnt_delta});
501	
502	                cut_idx <= cut_idx + 1;
503	                state   <= ST_CFAR_THR;
504	            end else begin
505	                state <= ST_COL_NEXT;
506	            end
507	        end
508	
509	        // ================================================================
510	        // ST_COL_NEXT: Advance to next Doppler column or finish
511	        // ================================================================
512	        ST_COL_NEXT: begin
513	            if (col_idx < NUM_DOPPLER_BINS - 1) begin
514	                col_idx      <= col_idx + 1;
515	                col_load_idx <= 0;
516	                mag_raddr    <= {6'd0, col_idx + 5'd1};
517	                state        <= ST_COL_LOAD;
518	            end else begin
519	                state <= ST_DONE;
520	            end
521	        end
522	
523	        // ================================================================
524	        // ST_DONE: Frame complete, return to idle
525	        // ================================================================
526	        ST_DONE: begin
527	            cfar_status <= 8'd0;
528	            state <= ST_IDLE;
529	
530	            `ifdef SIMULATION
531	            $display("[CFAR] Frame complete: %0d total detections", detect_count);
532	            `endif
533	        end
534	
535	        default: state <= ST_IDLE;
536	        endcase
537	    end
538	end
539	
540	// ============================================================================
541	// BRAM + LINE BUFFER INITIALIZATION (simulation only)
542	// ============================================================================
543	`ifdef SIMULATION
544	integer init_i;
545	initial begin
546	    for (init_i = 0; init_i < TOTAL_CELLS; init_i = init_i + 1)
547	        mag_mem[init_i] = 0;
548	    for (init_i = 0; init_i < NUM_RANGE_BINS; init_i = init_i + 1)
549	        col_buf[init_i] = 0;
550	end
551	`endif
552	
553	endmodule
554

