1	`timescale 1ns / 1ps
2	
3	/**
4	 * tb_cfar_ca.v
5	 *
6	 * Comprehensive testbench for cfar_ca.v (Cell-Averaging CFAR Detector).
7	 * Uses [PASS]/[FAIL] markers compatible with run_regression.sh.
8	 *
9	 * Test plan:
10	 *   T1:  CFAR disabled → simple threshold pass-through (backward-compatible)
11	 *   T2:  CA-CFAR with uniform noise floor → no detections
12	 *   T3:  CA-CFAR with single strong target → exactly 1 detection at correct bin
13	 *   T4:  CA-CFAR with two targets separated by > window size → 2 detections
14	 *   T5:  CA-CFAR edge handling → targets at range bin 0 and 63
15	 *   T6:  GO-CFAR mode with asymmetric noise → correct target detection
16	 *   T7:  SO-CFAR mode → lower threshold, more sensitive
17	 *   T8:  Alpha scaling → higher alpha reduces detections
18	 *   T9:  Guard cell effect → target neighbor doesn't raise threshold
19	 *   T10: Zero guard, zero train corner case
20	 *   T11: Reset during processing → clean recovery
21	 *   T12: Back-to-back frames → second frame processes correctly
22	 *   T13: detect_count accumulates across frames
23	 *   T14: cfar_busy asserts during processing, deasserts after
24	 */
25	
26	module tb_cfar_ca;
27	
28	// ============================================================================
29	// PARAMETERS
30	// ============================================================================
31	parameter NUM_RANGE   = 64;
32	parameter NUM_DOPPLER = 32;
33	parameter MAG_W       = 17;
34	parameter ALPHA_W     = 8;
35	parameter CLK_PERIOD  = 10;  // 100 MHz
36	
37	// ============================================================================
38	// DUT SIGNALS
39	// ============================================================================
40	reg clk;
41	reg reset_n;
42	
43	reg [31:0] doppler_data;
44	reg        doppler_valid;
45	reg [4:0]  doppler_bin_in;
46	reg [5:0]  range_bin_in;
47	reg        frame_complete;
48	
49	reg [3:0]  cfg_guard_cells;
50	reg [4:0]  cfg_train_cells;
51	reg [ALPHA_W-1:0] cfg_alpha;
52	reg [1:0]  cfg_cfar_mode;
53	reg        cfg_cfar_enable;
54	reg [15:0] cfg_simple_threshold;
55	
56	wire        detect_flag;
57	wire        detect_valid;
58	wire [5:0]  detect_range;
59	wire [4:0]  detect_doppler;
60	wire [MAG_W-1:0] detect_magnitude;
61	wire [MAG_W-1:0] detect_threshold;
62	wire [15:0] detect_count;
63	wire        cfar_busy;
64	wire [7:0]  cfar_status;
65	
66	// ============================================================================
67	// TEST TRACKING
68	// ============================================================================
69	integer pass_count;
70	integer fail_count;
71	integer test_num;
72	reg [255:0] test_name;
